import{_ as a,o as r,c as l,a2 as e}from"./chunks/framework.Cd7uensT.js";const b=JSON.parse('{"title":"机房管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features/room-management.md","filePath":"guide/features/room-management.md","lastUpdated":1781664302000}'),o={name:"guide/features/room-management.md"};function i(d,t,n,h,s,c){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="机房管理" tabindex="-1">机房管理 <a class="header-anchor" href="#机房管理" aria-label="Permalink to &quot;机房管理&quot;">​</a></h1><h2 id="机房管理-1" tabindex="-1">机房管理 <a class="header-anchor" href="#机房管理-1" aria-label="Permalink to &quot;机房管理&quot;">​</a></h2><p>机房管理用于维护数据中心的基础信息。</p><h3 id="新增机房" tabindex="-1">新增机房 <a class="header-anchor" href="#新增机房" aria-label="Permalink to &quot;新增机房&quot;">​</a></h3><ol><li>进入「机房管理」页面</li><li>点击「新增机房」按钮</li><li>填写机房信息：机房名称、位置、面积、负责人、联系电话、备注、机房图片</li><li>点击「确定」保存</li></ol><h3 id="删除机房" tabindex="-1">删除机房 <a class="header-anchor" href="#删除机房" aria-label="Permalink to &quot;删除机房&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">注意</p><p>删除机房前需确保该机房下没有机柜和设备。</p></div><h3 id="机房平面图" tabindex="-1">机房平面图 <a class="header-anchor" href="#机房平面图" aria-label="Permalink to &quot;机房平面图&quot;">​</a></h3><p>机房平面图以 2D 俯视图方式展示机房的物理布局，帮助运维人员直观掌握机房空间分配和设备部署情况。</p><h4 id="展示内容" tabindex="-1">展示内容 <a class="header-anchor" href="#展示内容" aria-label="Permalink to &quot;展示内容&quot;">​</a></h4><ul><li><strong>机柜分布</strong>：在平面图上标注每个机柜的位置，显示机柜编号</li><li><strong>区域划分</strong>：支持在平面图中标记不同功能区域（如服务器区、网络区、存储区、配电区等）</li><li><strong>通道标识</strong>：标注冷通道、热通道位置及方向</li><li><strong>基础设施标注</strong>：标注空调、配电柜、UPS、消防设备等基础设施位置</li></ul><h4 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td><strong>缩放平面图</strong></td><td>鼠标滚轮缩放</td></tr><tr><td><strong>平移视图</strong></td><td>鼠标拖拽空白区域</td></tr><tr><td><strong>查看机柜详情</strong></td><td>点击机柜位弹出信息面板</td></tr><tr><td><strong>查看设备统计</strong></td><td>鼠标悬停显示该区域设备数量统计</td></tr></tbody></table><h4 id="编辑平面图" tabindex="-1">编辑平面图 <a class="header-anchor" href="#编辑平面图" aria-label="Permalink to &quot;编辑平面图&quot;">​</a></h4><ol><li>进入机房详情页 → 「平面图」标签页</li><li>点击「编辑平面图」按钮</li><li>可拖拽调整机柜位置，添加或删除区域标注</li><li>编辑完成后保存</li></ol><h2 id="机柜管理" tabindex="-1">机柜管理 <a class="header-anchor" href="#机柜管理" aria-label="Permalink to &quot;机柜管理&quot;">​</a></h2><h3 id="新增机柜" tabindex="-1">新增机柜 <a class="header-anchor" href="#新增机柜" aria-label="Permalink to &quot;新增机柜&quot;">​</a></h3><ol><li>进入「机柜管理」页面</li><li>点击「新增机柜」按钮</li><li>填写机柜信息：机柜名称、所属机房、机柜高度(U数)、位置</li><li>点击「确定」保存</li></ol><h3 id="容量查看" tabindex="-1">容量查看 <a class="header-anchor" href="#容量查看" aria-label="Permalink to &quot;容量查看&quot;">​</a></h3><p>机柜列表显示：总U数、已用U数、剩余U数、使用率（可视化进度条）。</p><h3 id="批量导入导出机柜" tabindex="-1">批量导入导出机柜 <a class="header-anchor" href="#批量导入导出机柜" aria-label="Permalink to &quot;批量导入导出机柜&quot;">​</a></h3><h4 id="批量导入" tabindex="-1">批量导入 <a class="header-anchor" href="#批量导入" aria-label="Permalink to &quot;批量导入&quot;">​</a></h4><ol><li>点击「导入」按钮</li><li>下载导入模板（Excel/CSV 格式），模板包含：机柜名称、所属机房、机柜高度（U数）、位置编码等列</li><li>按模板格式填写多个机柜信息</li><li>上传文件，系统自动解析并批量创建机柜</li><li>导入完成后显示成功与失败记录详情</li></ol><h4 id="批量导出" tabindex="-1">批量导出 <a class="header-anchor" href="#批量导出" aria-label="Permalink to &quot;批量导出&quot;">​</a></h4><ol><li>在机柜列表设置筛选条件（按机房、按状态等）</li><li>点击「导出」按钮</li><li>选择导出格式（Excel/CSV）</li><li>导出的清单包含：机柜名称、所属机房、总U数、已用U数、使用率、位置编码等信息</li></ol><h2 id="_3d机柜可视化" tabindex="-1">3D机柜可视化 <a class="header-anchor" href="#_3d机柜可视化" aria-label="Permalink to &quot;3D机柜可视化&quot;">​</a></h2><p>3D可视化提供直观的机柜设备布局展示，基于三维渲染引擎实现。</p><h3 id="视图能力" tabindex="-1">视图能力 <a class="header-anchor" href="#视图能力" aria-label="Permalink to &quot;视图能力&quot;">​</a></h3><ul><li><strong>设备排布</strong>：在 3D 机柜模型中展示设备的实际安装位置，精确到 U 位</li><li><strong>设备面板</strong>：渲染设备前面板，展示指示灯、端口等外观特征</li><li><strong>空间感</strong>：通过三维视角直观展示机柜的立体空间和设备占用情况</li><li><strong>多机柜视图</strong>：支持切换到整排机柜或整个机房的 3D 概览视图</li></ul><h3 id="操作方式-1" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式-1" aria-label="Permalink to &quot;操作方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>方法</th></tr></thead><tbody><tr><td><strong>旋转视角</strong></td><td>鼠标左键拖拽</td></tr><tr><td><strong>缩放视图</strong></td><td>鼠标滚轮</td></tr><tr><td><strong>平移视图</strong></td><td>鼠标右键拖拽</td></tr><tr><td><strong>查看设备</strong></td><td>鼠标悬停显示设备信息</td></tr><tr><td><strong>设备详情</strong></td><td>点击设备弹出详情面板</td></tr></tbody></table><h3 id="设备状态颜色" tabindex="-1">设备状态颜色 <a class="header-anchor" href="#设备状态颜色" aria-label="Permalink to &quot;设备状态颜色&quot;">​</a></h3><table tabindex="0"><thead><tr><th>颜色</th><th>对应状态</th></tr></thead><tbody><tr><td>🟢 <strong>绿色</strong></td><td>运行中 — 设备正常运行</td></tr><tr><td>🟡 <strong>黄色</strong></td><td>维护中 — 设备正在维护</td></tr><tr><td>🔴 <strong>红色</strong></td><td>故障 — 设备出现异常</td></tr><tr><td>⚪ <strong>灰色</strong></td><td>已停用/已报废 — 设备不再使用</td></tr></tbody></table><h3 id="筛选与定位" tabindex="-1">筛选与定位 <a class="header-anchor" href="#筛选与定位" aria-label="Permalink to &quot;筛选与定位&quot;">​</a></h3><ul><li>支持按设备名称、类型快速搜索定位</li><li>搜索命中后，3D 视图自动聚焦到目标设备并高亮显示</li><li>支持按设备状态筛选显示</li></ul>',35)])])}const g=a(o,[["render",i]]);export{b as __pageData,g as default};
